  ChiselCircuitAnnotation,
  ChiselGeneratorAnnotation,
  ChiselOptions,
  ChiselOptionsView,
  DesignAnnotation,
  ThrowOnFirstErrorAnnotation
}
import firrtl.{annoSeqToSeq, seqToAnnoSeq, AnnotationSeq}
